    88→// ============================================================================
    89→// Vec<T>에 대한 조건부 Send/Sync 구현
    90→// ============================================================================
    91→
    92→/// Vec<T>는 T가 Send이면 Send
    93→pub struct Vec<T> {
    94→    data: *mut T,
    95→    len: usize,
    96→    capacity: usize,
    97→}
    98→
    99→// Vec<T>: Send if T: Send
   100→impl<T> Send for Vec<T> where T: Send { }
   101→
   102→// Vec<T>: Sync if T: Sync
   103→impl<T> Sync for Vec<T> where T: Sync { }
   104→
   105→// ============================================================================
   106→// Option<T>에 대한 조건부 Send/Sync 구현
   107→// ============================================================================
   108→
   109→pub enum Option<T> {
   110→    Some(T),
   111→    None,
   112→}
   113→
   114→// Option<T>: Send if T: Send
   115→impl<T> Send for Option<T> where T: Send { }
   116→
   117→// Option<T>: Sync if T: Sync
   118→impl<T> Sync for Option<T> where T: Sync { }
   119→
   120→// ============================================================================
   121→// Result<T, E>에 대한 조건부 Send/Sync 구현
   122→// ============================================================================
   123→
   124→pub enum Result<T, E> {
   125→    Ok(T),
   126→    Err(E),
   127→}
   128→
   129→// Result<T, E>: Send if T: Send and E: Send
   130→impl<T, E> Send for Result<T, E> where T: Send, E: Send { }
   131→
   132→// Result<T, E>: Sync if T: Sync and E: Sync
   133→impl<T, E> Sync for Result<T, E> where T: Sync, E: Sync { }
   134→
   135→// ============================================================================
   136→// Arc<T>: 원자적 참조 카운팅 (Atomic Reference Counting)
   137→// ============================================================================
   138→
   139→/// Arc<T>는 여러 소유자가 같은 데이터를 공유하되,
   140→/// 모든 소유자가 제거될 때까지 메모리를 유지합니다.
   141→pub struct Arc<T> {
   142→    ptr: *mut ArcInner<T>,
   143→}
   144→
   145→struct ArcInner<T> {
   146→    strong: u32,     // 강한 참조 카운트
   147→    weak: u32,       // 약한 참조 카운트
   148→    data: T,
   149→}
   150→
   151→// Arc<T>: Send if T: Send + Sync
   152→// 설명: Arc는 여러 스레드에서 공유되므로, T는 Send이면서 동시에
   153→//      스레드 간에 안전하게 공유될 수 있어야 합니다.
   154→impl<T> Send for Arc<T> where T: Send + Sync { }
   155→
   156→// Arc<T>: Sync if T: Send + Sync
   157→// 설명: Arc의 &을 여러 스레드에서 공유할 수 있으려면,
   158→//      T는 Send이면서 Sync여야 합니다.
   159→impl<T> Sync for Arc<T> where T: Send + Sync { }
   160→
   161→// ============================================================================
   162→// Mutex<T>: 상호 배제 락 (Mutual Exclusion Lock)
   163→// ============================================================================
   164→
   165→/// Mutex<T>는 내부 가변성(Interior Mutability)을 제공하면서
   166→/// 동시에 스레드 안전성을 보장하는 동기화 프리미티브입니다.
   167→pub struct Mutex<T> {
   168→    lock: bool,  // 간단한 락 구현 (실제로는 futex/platform mutex 사용)
   169→    data: T,
   170→}
   171→
   172→// Mutex<T>: Send if T: Send
   173→// 설명: Mutex<T>의 소유권을 다른 스레드로 이동할 수 있으려면,
   174→//      T가 Send여야 합니다.
   175→impl<T> Send for Mutex<T> where T: Send { }
   176→
   177→// Mutex<T>: Sync
   178→// 설명: Mutex<T>는 &Mutex<T>를 여러 스레드에서 공유할 수 있습니다.
   179→//      왜냐하면 lock()은 불변 참조로 호출되고, 내부적으로는
   180→//      배타성을 보장하기 때문입니다.
   181→impl<T> Sync for Mutex<T> where T: Send { }
   182→
   183→// ============================================================================
   184→// Rc<T>: 참조 카운팅 (Reference Counting, 단일 스레드용)
   185→// ============================================================================
   186→
   187→/// Rc<T>는 단일 스레드 전용 참조 카운팅입니다.
   188→/// 여러 스레드에서 사용하면 안전하지 않습니다.
   189→pub struct Rc<T> {
   190→    ptr: *mut RcInner<T>,
   191→}
   192→
   193→struct RcInner<T> {
   194→    strong: u32,  // 스레드 안전하지 않은 카운트
   195→    data: T,
   196→}
   197→
   198→// Rc<T>: !Send (절대로 Send가 아님)
   199→// 이것은 컴파일러에게 Rc<T>를 thread::spawn으로 전달할 수 없다는 것을 알립니다.
   200→// Rc의 refcount는 원자적이지 않기 때문입니다.
   201→pub trait RcSendBlock {}
   202→
   203→// ============================================================================
   204→// RefCell<T>: 동적 빌림 검사 (Dynamic Borrow Checking)
   205→// ============================================================================
   206→
   207→/// RefCell<T>는 런타임에 빌림 규칙을 검사합니다.
   208→/// 규칙 위반 시 panic()을 발생시킵니다.
   209→pub struct RefCell<T> {
   210→    borrow_count: i32,  // 양수: 불변 빌림 카운트, -1: 가변 빌림 중
   211→    data: T,
   212→}
   213→
   214→// RefCell<T>: !Sync (절대로 Sync가 아님)
   215→// 설명: RefCell의 borrow_count는 비원자적이므로,
   216→//      여러 스레드에서 동시에 접근하면 데이터 경합이 발생할 수 있습니다.
   217→pub trait RefCellSyncBlock {}
   218→
   219→// ============================================================================
   220→// 스레드 안전성 검증 함수들
   221→// ============================================================================
   222→
   223→/// 주어진 타입 T가 Send를 구현하는지 검증합니다.
   224→/// 컴파일 시에만 실행되며, 런타임 비용이 없습니다.
   225→fn assert_send<T: Send>() { }
   226→
   227→/// 주어진 타입 T가 Sync를 구현하는지 검증합니다.
   228→fn assert_sync<T: Sync>() { }
   229→
   230→/// 주어진 타입 T가 Send와 Sync 모두 구현하는지 검증합니다.
   231→fn assert_send_sync<T: Send + Sync>() { }
