     1→// ============================================================================
     2→// FreeLang Arc<T> - Atomic Reference Counting
     3→// ============================================================================
     4→//
     5→// 여러 스레드가 안전하게 같은 데이터를 공유할 수 있도록 하는
     6→// 원자적 참조 카운팅 구조입니다.
     7→//
     8→// 특징:
     9→// - 원자적 참조 카운트 (스레드 안전)
    10→// - 마지막 소유자가 drop될 때 메모리 해제
    11→// - Send + Sync: 스레드 간 안전한 소유권 이동 및 공유
    12→//
    13→// 작성일: 2026-03-02
    14→// 커밋: Phase B.1 (Week 2)
    15→
    16→use crate::sync::atomic::AtomicUsize;
    17→use crate::sync::atomic::Ordering;
    18→use std::ptr::NonNull;
    19→
    20→// ============================================================================
    21→// Arc의 내부 구조
    22→// ============================================================================
    23→
    24→/// Arc 내부에서 실제 데이터와 참조 카운트를 저장합니다.
    25→struct ArcInner<T> {
    26→    // 강한 참조 카운트 (Arc<T>의 개수)
    27→    strong: AtomicUsize,
    28→
    29→    // 약한 참조 카운트 (Weak<T>의 개수)
    30→    // 이번 단계에서는 생략 가능
    31→    weak: AtomicUsize,
    32→
    33→    // 실제 데이터
    34→    data: T,
    35→}
    36→
    37→/// Arc<T>: Atomic Reference Counted pointer
    38→///
    39→/// 여러 스레드가 소유할 수 있는 불변 데이터 공유 포인터입니다.
    40→pub struct Arc<T: ?Sized> {
    41→    // 원자적으로 접근 가능한 포인터
    42→    ptr: NonNull<ArcInner<T>>,
    43→}
    44→
    45→// ============================================================================
    46→// Arc의 기본 메서드
    47→// ============================================================================
    48→
    49→impl<T> Arc<T> {
    50→    /// 새로운 Arc<T>를 생성합니다.
    51→    ///
    52→    /// # 예제
    53→    ///
    54→    /// ```
    55→    /// let five = Arc::new(5);
    56→    /// ```
    57→    pub fn new(data: T) -> Arc<T> {
    58→        let boxed = Box::new(ArcInner {
    59→            strong: AtomicUsize::new(1),
    60→            weak: AtomicUsize::new(1),
    61→            data,
    62→        });
    63→
    64→        Arc {
    65→            ptr: NonNull::new(Box::into_raw(boxed)).unwrap(),
    66→        }
    67→    }
    68→
    69→    /// Arc 내부의 데이터를 얻습니다.
    70→    ///
    71→    /// 불변 참조이므로, 내용을 변경할 수 없습니다.
    72→    pub fn get_ref(&self) -> &T {
    73→        unsafe {
    74→            &self.ptr.as_ref().data
    75→        }
    76→    }
    77→
    78→    /// 참조 카운트를 반환합니다.
    79→    pub fn strong_count(this: &Arc<T>) -> usize {
    80→        unsafe {
    81→            this.ptr.as_ref().strong.load(Ordering::SeqCst)
    82→        }
    83→    }
    84→}
    85→
    86→// ============================================================================
    87→// Clone 구현: 참조 카운트 증가
    88→// ============================================================================
    89→
    90→impl<T: ?Sized> Clone for Arc<T> {
    91→    /// Arc를 clone하면 참조 카운트가 1 증가합니다.
    92→    ///
    93→    /// 각 clone은 같은 데이터를 가리키지만, 독립적인 소유자입니다.
    94→    fn clone(&self) -> Arc<T> {
    95→        // 원자적으로 참조 카운트 증가
    96→        unsafe {
    97→            self.ptr.as_ref().strong.fetch_add(1, Ordering::SeqCst);
    98→        }
    99→
   100→        Arc {
   101→            ptr: self.ptr,
   102→        }
   103→    }
   104→}
   105→
   106→// ============================================================================
   107→// Drop 구현: 참조 카운트 감소
   108→// ============================================================================
   109→
   110→impl<T: ?Sized> Drop for Arc<T> {
   111→    /// Arc를 drop하면 참조 카운트가 1 감소합니다.
   112→    ///
   113→    /// 참조 카운트가 0이 되면 내부 데이터도 drop됩니다.
   114→    fn drop(&mut self) {
   115→        unsafe {
   116→            // 참조 카운트를 원자적으로 1 감소
   117→            let strong = self.ptr.as_ref().strong.fetch_sub(1, Ordering::SeqCst);
   118→
   119→            // 참조 카운트가 0이 되면 메모리 해제
   120→            if strong == 1 {
   121→                // 데이터 drop
   122→                std::mem::drop(Box::from_raw(self.ptr.as_mut()));
   123→            }
   124→        }
   125→    }
   126→}
   127→
   128→// ============================================================================
   129→// Deref 구현: Arc<T>를 &T처럼 사용
   130→// ============================================================================
   131→
   132→impl<T: ?Sized> std::ops::Deref for Arc<T> {
   133→    type Target = T;
   134→
   135→    fn deref(&self) -> &T {
   136→        unsafe {
   137→            &self.ptr.as_ref().data
   138→        }
   139→    }
   140→}
   141→
   142→// ============================================================================
   143→// Send/Sync 구현
   144→// ============================================================================
   145→
   146→// Arc<T>: Send if T: Send + Sync
   147→//
   148→// 설명:
   149→// - T: Send이면, T의 소유권을 다른 스레드로 이동할 수 있습니다.
   150→// - T: Sync이면, &T를 여러 스레드에서 공유할 수 있습니다.
   151→// - Arc<T>가 한 스레드에서 다른 스레드로 이동할 때:
   152→//   1. 새 스레드는 Arc를 통해 &T를 얻습니다.
   153→//   2. &T를 여러 스레드에서 사용하려면 T: Sync여야 합니다.
   154→//   3. 참조 카운트는 원자적 연산으로 안전합니다.
   155→impl<T> Send for Arc<T>
   156→where
   157→    T: Send + Sync,
   158→{
   159→}
   160→
   161→// Arc<T>: Sync if T: Send + Sync
   162→//
   163→// 설명:
   164→// - &Arc<T>를 여러 스레드에서 공유할 수 있습니다.
   165→// - &Arc<T>를 통해 &T를 얻을 수 있습니다.
   166→// - 여러 스레드에서 &T를 공유하려면 T: Sync여야 합니다.
   167→// - clone() 시 참조 카운트는 원자적으로 증가합니다.
   168→impl<T> Sync for Arc<T>
   169→where
   170→    T: Send + Sync,
   171→{
   172→}
