     7→/// Absolute value
     8→pub fn abs(args: Vec<Value>) -> Result<Value, String> {
     9→    if args.is_empty() {
    10→        return Err("abs requires 1 argument".to_string());
    11→    }
    12→    Ok(Value::Number(args[0].to_number().abs()))
    13→}
    14→
    15→/// Square root
    16→pub fn sqrt(args: Vec<Value>) -> Result<Value, String> {
    17→    if args.is_empty() {
    18→        return Err("sqrt requires 1 argument".to_string());
    19→    }
    20→    let n = args[0].to_number();
    21→    if n < 0.0 {
    22→        return Err("Cannot take square root of negative number".to_string());
    23→    }
    24→    Ok(Value::Number(n.sqrt()))
    25→}
    26→
    27→/// Power (base^exponent)
    28→pub fn pow(args: Vec<Value>) -> Result<Value, String> {
    29→    if args.len() < 2 {
    30→        return Err("pow requires 2 arguments: base, exponent".to_string());
    31→    }
    32→    let base = args[0].to_number();
    33→    let exponent = args[1].to_number();
    34→    Ok(Value::Number(base.powf(exponent)))
    35→}
    36→
    37→/// Natural logarithm
    38→pub fn ln(args: Vec<Value>) -> Result<Value, String> {
    39→    if args.is_empty() {
    40→        return Err("ln requires 1 argument".to_string());
    41→    }
    42→    let n = args[0].to_number();
    43→    if n <= 0.0 {
    44→        return Err("Cannot take logarithm of non-positive number".to_string());
