    40→/// Get character at index
    41→pub fn char_at(args: Vec<Value>) -> Result<Value, String> {
    42→    if args.len() < 2 {
    43→        return Err("char_at requires 2 arguments: string, index".to_string());
    44→    }
    45→    let s = args[0].to_string();
    46→    let index = args[1].to_number() as usize;
    47→
    48→    if index < s.len() {
    49→        Ok(Value::String(s.chars().nth(index).unwrap().to_string()))
    50→    } else {
    51→        Err("Index out of bounds".to_string())
    52→    }
    53→}
    54→
    55→/// Get substring
    56→pub fn substring(args: Vec<Value>) -> Result<Value, String> {
    57→    if args.len() < 3 {
    58→        return Err("substring requires 3 arguments: string, start, end".to_string());
    59→    }
    60→    let s = args[0].to_string();
    61→    let start = args[1].to_number() as usize;
    62→    let end = args[2].to_number() as usize;
    63→
    64→    let chars: Vec<char> = s.chars().collect();
    65→    if start >= chars.len() || end > chars.len() || start > end {
    66→        return Err("Invalid substring range".to_string());
    67→    }
    68→
    69→    let result: String = chars[start..end].iter().collect();
    70→    Ok(Value::String(result))
    71→}
    72→
    73→/// Split string by delimiter
    74→pub fn split(args: Vec<Value>) -> Result<Value, String> {
    75→    if args.len() < 2 {
    76→        return Err("split requires 2 arguments: string, delimiter".to_string());
    77→    }
    78→    let s = args[0].to_string();
    79→    let delimiter = args[1].to_string();
    80→
    81→    let parts: Vec<Value> = s
    82→        .split(&delimiter)
    83→        .map(|part| Value::String(part.to_string()))
    84→        .collect();
    85→
    86→    Ok(Value::array(parts))
    87→}
    88→
    89→/// Join array elements with delimiter
    90→pub fn join(args: Vec<Value>) -> Result<Value, String> {
    91→    if args.len() < 2 {
    92→        return Err("join requires 2 arguments: array, delimiter".to_string());
    93→    }
    94→
    95→    let delimiter = args[1].to_string();
    96→
    97→    match &args[0] {
    98→        Value::Array(arr) => {
    99→            let arr_ref = arr.borrow();
   100→            let parts: Vec<String> = arr_ref
   101→                .iter()
   102→                .map(|v| v.to_string())
   103→                .collect();
   104→            Ok(Value::String(parts.join(&delimiter)))
   105→        }
   106→        _ => Err("First argument must be an array".to_string())
   107→    }
   108→}
