     4→use crate::core::Value;
     5→
     6→/// Get array length
     7→pub fn length(args: Vec<Value>) -> Result<Value, String> {
     8→    if args.is_empty() {
     9→        return Err("length requires 1 argument".to_string());
    10→    }
    11→
    12→    match &args[0] {
    13→        Value::Array(arr) => {
    14→            Ok(Value::Number(arr.borrow().len() as f64))
    15→        }
    16→        _ => Err("Argument must be an array".to_string())
    17→    }
    18→}
    19→
    20→/// Push element to array
    21→pub fn push(args: Vec<Value>) -> Result<Value, String> {
    22→    if args.len() < 2 {
    23→        return Err("push requires 2 arguments: array, value".to_string());
    24→    }
    25→
    26→    match &args[0] {
    27→        Value::Array(arr) => {
    28→            arr.borrow_mut().push(args[1].clone());
    29→            Ok(Value::Number(arr.borrow().len() as f64))
    30→        }
    31→        _ => Err("First argument must be an array".to_string())
    32→    }
    33→}
    34→
    35→/// Pop element from array
    36→pub fn pop(args: Vec<Value>) -> Result<Value, String> {
    37→    if args.is_empty() {
    38→        return Err("pop requires 1 argument".to_string());
    39→    }
    40→
    41→    match &args[0] {
    42→        Value::Array(arr) => {
    43→            match arr.borrow_mut().pop() {
    44→                Some(value) => Ok(value),
    45→                None => Ok(Value::Null)
    46→            }
    47→        }
    48→        _ => Err("Argument must be an array".to_string())
    49→    }
    50→}
    51→
    52→/// Get element at index
    53→pub fn get(args: Vec<Value>) -> Result<Value, String> {
    54→    if args.len() < 2 {
    55→        return Err("get requires 2 arguments: array, index".to_string());
    56→    }
    57→
    58→    match &args[0] {
    59→        Value::Array(arr) => {
    60→            let index = args[1].to_number() as usize;
    61→            let arr_ref = arr.borrow();
    62→            if index < arr_ref.len() {
    63→                Ok(arr_ref[index].clone())
    64→            } else {
    65→                Ok(Value::Null)
    66→            }
    67→        }
    68→        _ => Err("First argument must be an array".to_string())
    69→    }
    70→}
    71→
    72→/// Set element at index
    73→pub fn set(args: Vec<Value>) -> Result<Value, String> {
    74→    if args.len() < 3 {
    75→        return Err("set requires 3 arguments: array, index, value".to_string());
    76→    }
    77→
    78→    match &args[0] {
    79→        Value::Array(arr) => {
    80→            let index = args[1].to_number() as usize;
    81→            let mut arr_mut = arr.borrow_mut();
    82→            if index < arr_mut.len() {
    83→                arr_mut[index] = args[2].clone();
    84→                Ok(Value::Null)
    85→            } else {
    86→                Err("Index out of bounds".to_string())
    87→            }
    88→        }
    89→        _ => Err("First argument must be an array".to_string())
    90→    }
    91→}
    92→
    93→/// Slice array from start to end
    94→pub fn slice(args: Vec<Value>) -> Result<Value, String> {
    95→    if args.len() < 3 {
    96→        return Err("slice requires 3 arguments: array, start, end".to_string());
    97→    }
    98→
    99→    match &args[0] {
   100→        Value::Array(arr) => {
   101→            let start = args[1].to_number() as usize;
   102→            let end = args[2].to_number() as usize;
   103→            let arr_ref = arr.borrow();
   104→
   105→            if start >= arr_ref.len() || end > arr_ref.len() || start > end {
   106→                return Err("Invalid slice range".to_string());
   107→            }
   108→
   109→            let sliced: Vec<Value> = arr_ref[start..end].to_vec();
   110→            Ok(Value::array(sliced))
   111→        }
   112→        _ => Err("First argument must be an array".to_string())
   113→    }
   114→}
   115→
   116→/// Find index of element
   117→pub fn index_of(args: Vec<Value>) -> Result<Value, String> {
   118→    if args.len() < 2 {
   119→        return Err("index_of requires 2 arguments: array, value".to_string());
   120→    }
   121→
   122→    match &args[0] {
   123→        Value::Array(arr) => {
   124→            let arr_ref = arr.borrow();
   125→            for (i, item) in arr_ref.iter().enumerate() {
   126→                if item.equals(&args[1]) {
   127→                    return Ok(Value::Number(i as f64));
   128→                }
   129→            }
   130→            Ok(Value::Number(-1.0))
   131→        }
   132→        _ => Err("First argument must be an array".to_string())
   133→    }
   134→}
   135→
   136→/// Check if array contains value
   137→pub fn contains(args: Vec<Value>) -> Result<Value, String> {
   138→    if args.len() < 2 {
   139→        return Err("contains requires 2 arguments: array, value".to_string());
   140→    }
   141→
   142→    match &args[0] {
   143→        Value::Array(arr) => {
   144→            let arr_ref = arr.borrow();
   145→            for item in arr_ref.iter() {
   146→                if item.equals(&args[1]) {
   147→                    return Ok(Value::Bool(true));
   148→                }
   149→            }
   150→            Ok(Value::Bool(false))
   151→        }
   152→        _ => Err("First argument must be an array".to_string())
   153→    }
   154→}
   155→
   156→/// Reverse array in place
   157→pub fn reverse(args: Vec<Value>) -> Result<Value, String> {
   158→    if args.is_empty() {
   159→        return Err("reverse requires 1 argument".to_string());
   160→    }
   161→
   162→    match &args[0] {
   163→        Value::Array(arr) => {
   164→            arr.borrow_mut().reverse();
   165→            Ok(Value::Null)
   166→        }
   167→        _ => Err("Argument must be an array".to_string())
   168→    }
   169→}
   170→
   171→/// Sort array (numeric/lexical)
   172→pub fn sort(args: Vec<Value>) -> Result<Value, String> {
   173→    if args.is_empty() {
   174→        return Err("sort requires 1 argument".to_string());
   175→    }
   176→
   177→    match &args[0] {
   178→        Value::Array(arr) => {
   179→            arr.borrow_mut().sort_by(|a, b| {
   180→                a.to_number()
   181→                    .partial_cmp(&b.to_number())
   182→                    .unwrap_or(std::cmp::Ordering::Equal)
   183→            });
   184→            Ok(Value::Null)
   185→        }
   186→        _ => Err("Argument must be an array".to_string())
   187→    }
   188→}
   189→
   190→/// Join array elements into string
   191→pub fn join(args: Vec<Value>) -> Result<Value, String> {
   192→    if args.len() < 2 {
   193→        return Err("join requires 2 arguments: array, delimiter".to_string());
   194→    }
   195→
   196→    match &args[0] {
   197→        Value::Array(arr) => {
   198→            let delimiter = args[1].to_string();
   199→            let arr_ref = arr.borrow();
   200→            let parts: Vec<String> = arr_ref
   201→                .iter()
   202→                .map(|v| v.to_string())
   203→                .collect();
   204→            Ok(Value::String(parts.join(&delimiter)))
   205→        }
   206→        _ => Err("First argument must be an array".to_string())
   207→    }
   208→}
