     9→/// Sleep for milliseconds
    10→pub fn sleep(args: Vec<Value>) -> Result<Value, String> {
    11→    if args.is_empty() {
    12→        return Err("sleep requires 1 argument: milliseconds".to_string());
    13→    }
    14→
    15→    let ms = args[0].to_number() as u64;
    16→    std::thread::sleep(std::time::Duration::from_millis(ms));
    17→    Ok(Value::Null)
    18→}
    19→
    20→/// Exit program with exit code
    21→pub fn exit(args: Vec<Value>) -> Result<Value, String> {
    22→    let code = if args.is_empty() {
    23→        0
    24→    } else {
    25→        args[0].to_number() as i32
    26→    };
    27→    process::exit(code);
    28→}
    29→
    30→/// Get environment variable
    31→pub fn getenv(args: Vec<Value>) -> Result<Value, String> {
    32→    if args.is_empty() {
    33→        return Err("getenv requires 1 argument: variable name".to_string());
    34→    }
    35→
    36→    let var_name = args[0].to_string();
    37→    match env::var(&var_name) {
    38→        Ok(value) => Ok(Value::String(value)),
    39→        Err(_) => Ok(Value::Null)
    40→    }
    41→}
    42→
    43→/// Set environment variable
    44→pub fn setenv(args: Vec<Value>) -> Result<Value, String> {
    45→    if args.len() < 2 {
    46→        return Err("setenv requires 2 arguments: name, value".to_string());
    47→    }
    48→
    49→    let var_name = args[0].to_string();
    50→    let var_value = args[1].to_string();
    51→    env::set_var(&var_name, &var_value);
    52→    Ok(Value::Null)
    53→}
    54→
    55→/// Get current Unix timestamp (milliseconds)
    56→pub fn time_ms(args: Vec<Value>) -> Result<Value, String> {
    57→    let _ = args;
    58→    match SystemTime::now().duration_since(UNIX_EPOCH) {
    59→        Ok(duration) => Ok(Value::Number(duration.as_millis() as f64)),
    60→        Err(_) => Err("System time error".to_string())
    61→    }
    62→}
    63→
    64→/// Get current Unix timestamp (seconds)
    65→pub fn time(args: Vec<Value>) -> Result<Value, String> {
    66→    let _ = args;
    67→    match SystemTime::now().duration_since(UNIX_EPOCH) {
    68→        Ok(duration) => Ok(Value::Number(duration.as_secs() as f64)),
    69→        Err(_) => Err("System time error".to_string())
    70→    }
    71→}
    72→
    73→/// Generate random number between 0 and 1
    74→pub fn random(_args: Vec<Value>) -> Result<Value, String> {
    75→    use std::time::{SystemTime};
    76→
    77→    // Simple pseudo-random using system time
    78→    let nanos = SystemTime::now()
    79→        .duration_since(UNIX_EPOCH)
    80→        .map(|d| d.subsec_nanos())
    81→        .unwrap_or(0);
    82→
    83→    let random_val = ((nanos as f64) % 1000000.0) / 1000000.0;
    84→    Ok(Value::Number(random_val))
    85→}
    86→
    87→/// Get CPU count
    88→pub fn cpu_count(_args: Vec<Value>) -> Result<Value, String> {
    89→    // Use std library to detect CPU count
    90→    let count = std::thread::available_parallelism()
    91→        .map(|n| n.get())
    92→        .unwrap_or(1);
    93→    Ok(Value::Number(count as f64))
    94→}
