// 단계: Phase C.1 (Week 1)

/// 값을 정수로 변환합니다.
///
/// # 예제
/// ```
/// assert_eq!(to_int("42"), 42);
/// assert_eq!(to_int(3.7), 3);
/// assert_eq!(to_int(true), 1);
/// ```
pub fn to_int(value: FlValue) -> Result<i64, TypeError> {
    match value {
        FlValue::Int(n)    => Ok(n),
        FlValue::Float(f)  => Ok(f as i64),
        FlValue::Str(s)    => s.parse::<i64>()
                                .map_err(|_| TypeError::ParseError(s)),
        FlValue::Bool(b)   => Ok(if b { 1 } else { 0 }),
        FlValue::Null      => Ok(0),
        other              => Err(TypeError::UnsupportedConversion(other.type_name())),
    }
}

pub fn to_float(value: FlValue) -> Result<f64, TypeError> { ... }
pub fn to_string(value: FlValue) -> String { ... }
pub fn to_bool(value: FlValue) -> bool { ... }
pub fn type_of(value: FlValue) -> &'static str { ... }
pub fn is_null(value: FlValue) -> bool { ... }

/// TypeError: 타입 변환 에러
#[derive(Debug, PartialEq)]
pub enum TypeError {
    ParseError(String),
    UnsupportedConversion(String),
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test] fn test_to_int_from_string() { ... }    // "42" -> 42
    #[test] fn test_to_int_from_float() { ... }     // 3.7 -> 3
    #[test] fn test_to_int_from_bool() { ... }      // true -> 1
    #[test] fn test_to_int_error() { ... }          // "abc" -> Err
    #[test] fn test_to_float_from_string() { ... }
    #[test] fn test_to_string_from_int() { ... }
    #[test] fn test_to_string_from_null() { ... }   // null -> "null"
    #[test] fn test_to_bool_truthy() { ... }        // 1, "hello", [1] -> true
    #[test] fn test_to_bool_falsy() { ... }         // 0, "", null -> false
    #[test] fn test_type_of_values() { ... }        // type_of(42) -> "int"
    #[test] fn test_is_null_true() { ... }
    #[test] fn test_is_null_false() { ... }
}
